function solve(n, edges, k) {
    if (edges.length === 0) {
        return 0;
    }
    edges.sort((a, b) => a[2] - b[2]);
    let left = 0;
    let right = edges[edges.length - 1][2];

    function countComponents(t) {
        const parent = Array(n).fill().map((_, i) => i);
        const rank = Array(n).fill(1);

        function find(x) {
            if (parent[x] !== x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        function union(x, y) {
            const fx = find(x);
            const fy = find(y);
            if (fx === fy) return;
            if (rank[fx] < rank[fy]) {
                parent[fx] = fy;
            } else {
                parent[fy] = fx;
                rank[fx] += rank[fy];
            }
        }

        for (const [u, v, time] of edges) {
            if (time > t) {
                union(u, v);
            }
        }

        const roots = new Set();
        for (let i = 0; i < n; i++) {
            roots.add(find(i));
        }
        return roots.size;
    }

    while (left < right) {
        const mid = Math.floor((left + right) / 2);
        const components = countComponents(mid);
        if (components >= k) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }

    return left;
}
